#!/usr/bin/env python3
from __future__ import annotations

import argparse
import re
import sys
from pathlib import Path


REQUIRED_FRAGMENTS = [
    "# Отчёт Artifact Eval:",
    "Schema: artifact-eval/v1",
    "Status:",
    "Target:",
    "Generated by: eval-artifact.py",
    "## Сводка",
    "## Кейсы",
    "## Проверки",
    "## Сравнение baseline и guided",
    "## Вердикт",
]


def read_text(path: Path) -> str:
    return path.read_text(encoding="utf-8", errors="ignore") if path.exists() else ""


def metric_pair(text: str, name: str) -> tuple[int, int] | None:
    match = re.search(rf"{re.escape(name)}:\s*(\d+)/(\d+)\s*\(", text)
    if not match:
        return None
    return int(match.group(1)), int(match.group(2))


def count_table_rows(text: str, heading: str) -> int:
    pattern = re.compile(rf"(?ms)^##\s+{re.escape(heading)}\s*$\n(.*?)(?=^##\s+|\Z)")
    match = pattern.search(text)
    if not match:
        return 0
    return sum(1 for line in match.group(1).splitlines() if line.startswith("| ") and not line.startswith("| ---"))


def validate_report(path: Path) -> list[str]:
    errors: list[str] = []
    text = read_text(path)
    if not text.strip():
        return [f"{path}: report пустой"]
    if len(text.strip()) < 900:
        errors.append(f"{path}: report выглядит фиктивным или слишком коротким")

    for fragment in REQUIRED_FRAGMENTS:
        if fragment not in text:
            errors.append(f"{path}: отсутствует обязательный фрагмент `{fragment}`")

    if re.search(r"<[^>\n]+>|TODO|TBD|placeholder|stub|fake report", text, flags=re.IGNORECASE):
        errors.append(f"{path}: report содержит placeholder/fake marker")

    status_match = re.search(r"^Status:\s*(PASS|FAIL)\s*$", text, flags=re.MULTILINE)
    if not status_match:
        errors.append(f"{path}: не найден валидный `Status: PASS|FAIL`")

    for metric in ["case_pass_rate", "assertion_pass_rate", "trigger_accuracy"]:
        pair = metric_pair(text, metric)
        if pair is None:
            errors.append(f"{path}: не найден metric `{metric}`")
            continue
        passed, total = pair
        if total <= 0:
            errors.append(f"{path}: metric `{metric}` имеет нулевой denominator")
        if passed < 0 or passed > total:
            errors.append(f"{path}: metric `{metric}` некорректен: {passed}/{total}")

    if count_table_rows(text, "Кейсы") < 3:
        errors.append(f"{path}: нужно минимум 3 case rows")
    if count_table_rows(text, "Проверки") < 5:
        errors.append(f"{path}: нужно минимум 5 assertion rows")

    if "Target: " in text:
        target = re.search(r"^Target:\s*(.+?)\s*$", text, flags=re.MULTILINE)
        if target and target.group(1).strip() in {"", "-", "unknown", "<target>"}:
            errors.append(f"{path}: target не заполнен")

    return errors


def main() -> int:
    parser = argparse.ArgumentParser(description="Validate artifact-eval markdown reports.")
    parser.add_argument("reports", nargs="+", help="Report markdown files to validate.")
    args = parser.parse_args()

    errors: list[str] = []
    for item in args.reports:
        matches = sorted(Path().glob(item)) if any(ch in item for ch in "*?[") else [Path(item)]
        if not matches:
            errors.append(f"report not found: {item}")
            continue
        for path in matches:
            errors.extend(validate_report(path))

    if errors:
        print("ARTIFACT EVAL REPORT НЕВАЛИДЕН")
        for error in errors:
            print("-", error)
        return 1

    print("ARTIFACT EVAL REPORT ВАЛИДЕН")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
